    "backgroundId": "bg-table",
    "standings": [
      {
        "characterId": "shiyue",
        "position": "center",
        "standingId": "serious"
      }
    ],
    "speakerCharacterId": null,
    "speakerNameOverride": null,
    "text": "読んで、守って、数えて。そのうえで——詩玥の手が、最後の一枚へと、伸びる。",
