    "standings": [
      {
        "characterId": "shiyue",
        "position": "left",
        "standingId": "default"
      },
      {
        "characterId": "mamori",
        "position": "right",
        "standingId": "default"
      }
    ],
    "speakerCharacterId": "mamori",
    "speakerNameOverride": null,
    "text": "……知ってる? 九つの宝が揃うと、願いが一つ叶う、という俗説。",
