    "backgroundId": "bg-dojo-dusk",
    "standings": [
      {
        "characterId": "shiyue",
        "position": "left",
        "standingId": "smile"
      },
      {
        "characterId": "mamori",
        "position": "right",
        "standingId": "default"
      }
    ],
    "speakerCharacterId": "shiyue",
    "speakerNameOverride": null,
    "text": "あー、それネ。マモリ、前は「確率的根拠なし」って、ばっさりだったノに。",
